<template><view class="page"><view class="notice">请说明费用争议原因，可补充现场照片或凭证。门店处理后会在订单结算单中更新处理结果。</view><textarea v-model.trim="reason" class="reason" maxlength="500" placeholder="请填写具体争议原因"></textarea><view class="section-title">补充证据（最多6张）</view><view class="image-grid"><view v-for="(image,index) in images" :key="image" class="image-box"><image :src="image" mode="aspectFill"/><text @click="remove(index)">×</text></view><view v-if="images.length<6" class="add-image" @click="choose">+</view></view><button class="submit" :loading="submitting" @click="submit">提交争议</button></view></template>
<script setup>import{ref}from'vue';import{onLoad}from'@dcloudio/uni-app';import{disputeRentalSettlement,uploadRentalEvidence}from'../../api/rental';const id=ref(0),reason=ref(''),images=ref([]),submitting=ref(false);onLoad(q=>{id.value=Number(q.id)});const choose=()=>uni.chooseImage({count:6-images.value.length,sizeType:['compressed'],success:r=>{images.value.push(...r.tempFilePaths)}});const remove=i=>images.value.splice(i,1);const submit=async()=>{if(!reason.value)return uni.showToast({title:'请填写争议原因',icon:'none'});submitting.value=true;try{uni.showLoading({title:'上传证据',mask:true});const evidence=[];for(const path of images.value)evidence.push(await uploadRentalEvidence(path));await disputeRentalSettlement(id.value,reason.value,evidence);uni.hideLoading();uni.showToast({title:'争议已提交',icon:'success'});setTimeout(()=>uni.navigateBack(),600)}catch(e){uni.hideLoading();uni.showToast({title:e.msg||'提交失败',icon:'none'})}finally{submitting.value=false}}</script>
<style scoped>.page{min-height:100vh;padding:32rpx;background:#f5f7fa}.notice{padding:22rpx;border-radius:8rpx;background:#eff6ff;color:#42658e;font-size:24rpx;line-height:1.6}.reason{width:100%;height:240rpx;margin-top:22rpx;padding:20rpx;border-radius:8rpx;background:#fff;box-sizing:border-box;color:#1f2937;font-size:26rpx;line-height:1.5}.section-title{margin:30rpx 0 16rpx;color:#374151;font-size:27rpx;font-weight:700}.image-grid{display:flex;flex-wrap:wrap;gap:16rpx}.image-box,.add-image{position:relative;width:200rpx;height:200rpx;border-radius:8rpx;overflow:hidden}.image-box image{width:100%;height:100%}.image-box text{position:absolute;top:0;right:0;width:44rpx;height:44rpx;background:rgba(0,0,0,.55);color:#fff;text-align:center;line-height:44rpx}.add-image{display:flex;align-items:center;justify-content:center;border:1rpx dashed #94a3b8;background:#fff;color:#94a3b8;font-size:60rpx}.submit{margin-top:48rpx;border-radius:8rpx;background:#1677ff;color:#fff;font-size:28rpx}</style>
